/* Minimal QR Code generator (byte mode, auto version/EC) — MIT-style, no deps.
   Renders to a canvas. Compact implementation adapted for this project.
   Exposes: window.QRCode.toCanvas(canvas, text, opts)                        */
(function(){
  // ---- Galois field tables ----
  var EXP=[],LOG=[];
  (function(){for(var i=0,x=1;i<255;i++){EXP[i]=x;LOG[x]=i;x<<=1;if(x&256)x^=285;}for(i=255;i<512;i++)EXP[i]=EXP[i-255];})();
  function gmul(a,b){return a===0||b===0?0:EXP[LOG[a]+LOG[b]];}
  function genPoly(n){var p=[1];for(var i=0;i<n;i++){var np=[0];for(var j=0;j<p.length;j++){np[j]^=gmul(p[j],EXP[i]);np[j+1]=(np[j+1]||0)^p[j];}p=np;}return p;}
  function ecc(data,n){var res=data.slice().concat(new Array(n).fill(0));var g=genPoly(n);
    for(var i=0;i<data.length;i++){var c=res[i];if(c!==0)for(var j=0;j<g.length;j++)res[i+j]^=gmul(g[j],c);}
    return res.slice(data.length);}

  // capacity table for byte mode, EC level M, versions 1..10
  var CAP={1:14,2:26,3:42,4:62,5:84,6:106,7:122,8:152,9:180,10:213};
  var ECPB={1:10,2:16,3:26,4:18,5:24,6:16,7:18,8:22,9:22,10:26}; // ec codewords per block (M)
  var BLOCKS={1:1,2:1,3:1,4:2,5:2,6:4,7:4,8:4,9:5,10:5};
  var TOTAL={1:26,2:44,3:70,4:100,5:134,6:172,7:196,8:242,9:292,10:346};

  function pickVersion(len){for(var v=1;v<=10;v++)if(len<=CAP[v])return v;throw new Error("Data too long for QR");}

  function buildMatrix(version, bits){
    var size=version*4+17;
    var m=[],reserved=[];
    for(var i=0;i<size;i++){m.push(new Array(size).fill(null));reserved.push(new Array(size).fill(false));}
    function finder(r,c){for(var dr=-1;dr<=7;dr++)for(var dc=-1;dc<=7;dc++){var rr=r+dr,cc=c+dc;if(rr<0||cc<0||rr>=size||cc>=size)continue;
      var on=(dr>=0&&dr<=6&&(dc===0||dc===6))||(dc>=0&&dc<=6&&(dr===0||dr===6))||(dr>=2&&dr<=4&&dc>=2&&dc<=4);
      m[rr][cc]=on?1:0;reserved[rr][cc]=true;}}
    finder(0,0);finder(0,size-7);finder(size-7,0);
    // timing
    for(var t=8;t<size-8;t++){var b=t%2===0?1:0;if(m[6][t]===null){m[6][t]=b;reserved[6][t]=true;}if(m[t][6]===null){m[t][6]=b;reserved[t][6]=true;}}
    // dark module
    m[size-8][8]=1;reserved[size-8][8]=true;
    // alignment (versions>=2): single centre pattern
    if(version>=2){var pos=size-7;align(pos-0,pos-0);
      function align(cr,cc){/*noop placeholder*/}
      var ac=version*4+10; // centre
      for(var dr=-2;dr<=2;dr++)for(var dc=-2;dc<=2;dc++){var rr=ac+dr,cc2=ac+dc;
        var on=(Math.abs(dr)===2||Math.abs(dc)===2||(dr===0&&dc===0))?1:0;
        if(m[rr]&&m[rr][cc2]===null){m[rr][cc2]=on;reserved[rr][cc2]=true;}}}
    // reserve format areas
    for(var k=0;k<9;k++){if(k!==6){reserved[8][k]=true;reserved[k][8]=true;}}
    for(k=0;k<8;k++){reserved[8][size-1-k]=true;reserved[size-1-k][8]=true;}
    // place data zig-zag
    var idx=0,up=true;
    for(var col=size-1;col>0;col-=2){if(col===6)col--;
      for(var row2=0;row2<size;row2++){var r2=up?size-1-row2:row2;
        for(var c2=0;c2<2;c2++){var cc3=col-c2;
          if(!reserved[r2][cc3]){var bit=idx<bits.length?bits[idx]:0;idx++;
            var mask=(r2+cc3)%2===0?1:0; // mask 0
            m[r2][cc3]=bit^mask;}}}
      up=!up;}
    // format info (EC=M=00, mask=0) precomputed
    placeFormat(m,size,"101010000010010");
    return m;
  }
  function placeFormat(m,size,fmt){
    var bits=fmt.split("").map(Number);
    // around top-left
    var coords1=[[8,0],[8,1],[8,2],[8,3],[8,4],[8,5],[8,7],[8,8],[7,8],[5,8],[4,8],[3,8],[2,8],[1,8],[0,8]];
    for(var i=0;i<15;i++){var rc=coords1[i];m[rc[0]][rc[1]]=bits[i];}
    // duplicate
    for(i=0;i<7;i++)m[size-1-i][8]=bits[i];
    for(i=0;i<8;i++)m[8][size-1-(7-i)]=bits[7+i];
  }

  function encode(text){
    var bytes=unescape(encodeURIComponent(text)).split("").map(function(c){return c.charCodeAt(0);});
    var version=pickVersion(bytes.length);
    var bits=[];
    function push(val,len){for(var i=len-1;i>=0;i--)bits.push((val>>i)&1);}
    push(4,4); push(bytes.length,8);
    bytes.forEach(function(b){push(b,8);});
    // terminator + pad to codewords
    var totalDataCW=TOTAL[version]-ECPB[version]*BLOCKS[version];
    var maxBits=totalDataCW*8;
    for(var i=0;i<4&&bits.length<maxBits;i++)bits.push(0);
    while(bits.length%8!==0)bits.push(0);
    var cw=[];for(i=0;i<bits.length;i+=8){var v=0;for(var j=0;j<8;j++)v=(v<<1)|bits[i+j];cw.push(v);}
    var pads=[236,17],pi=0;while(cw.length<totalDataCW)cw.push(pads[pi++%2]);
    // split into blocks, compute EC
    var nb=BLOCKS[version],ecn=ECPB[version];
    var per=Math.floor(totalDataCW/nb),rem=totalDataCW%nb;
    var dblocks=[],eblocks=[],off=0;
    for(i=0;i<nb;i++){var sz=per+(i>=nb-rem?1:0);var blk=cw.slice(off,off+sz);off+=sz;dblocks.push(blk);eblocks.push(ecc(blk,ecn));}
    // interleave
    var out=[],maxd=Math.max.apply(null,dblocks.map(function(b){return b.length;}));
    for(i=0;i<maxd;i++)for(j=0;j<nb;j++)if(i<dblocks[j].length)out.push(dblocks[j][i]);
    for(i=0;i<ecn;i++)for(j=0;j<nb;j++)out.push(eblocks[j][i]);
    var finalBits=[];out.forEach(function(b){for(var k=7;k>=0;k--)finalBits.push((b>>k)&1);});
    return {version:version,matrix:buildMatrix(version,finalBits)};
  }

  window.QRCode={
    toCanvas:function(canvas,text,opts){
      opts=opts||{};
      try{
        var r=encode(text),m=r.matrix,size=m.length,quiet=2;
        var scale=opts.scale||Math.max(2,Math.floor((opts.width||150)/(size+quiet*2)));
        var dim=(size+quiet*2)*scale;
        canvas.width=dim;canvas.height=dim;
        var ctx=canvas.getContext("2d");
        ctx.fillStyle=opts.light||"#ffffff";ctx.fillRect(0,0,dim,dim);
        ctx.fillStyle=opts.dark||"#12261D";
        for(var y=0;y<size;y++)for(var x=0;x<size;x++)if(m[y][x])ctx.fillRect((x+quiet)*scale,(y+quiet)*scale,scale,scale);
      }catch(e){var c=canvas.getContext("2d");canvas.width=canvas.height=150;c.fillStyle="#eee";c.fillRect(0,0,150,150);c.fillStyle="#999";c.font="12px sans-serif";c.fillText("QR error",45,78);}
    }
  };
})();
